<?php
 declare(strict_types=1); namespace tapmeppe\composer\database\seeders; use Illuminate\Support\Facades\DB; class ContactsUserUpdate extends \tapmeppe\composer\helpers\Seeder { public function runInner(array $parameters) { if ($parameters['role'] == 'Administrator') return false; if (isset($parameters['id'])) { $id = $parameters['id']; unset($parameters['id']); } else $id = DB::table('users')->where('email', $parameters['email'])->first()->id; if (isset($parameters['password'])) $parameters['password'] = password_hash($parameters['password'], PASSWORD_BCRYPT, ['cost' => 10]); if (isset($parameters['role'])) { $parameters['role_id'] = DB::table('roles')->where('name', $parameters['role'])->first()->id; unset($parameters['role']); } DB::table('users')->updateOrInsert(['id' => $id], $parameters); return true; } } 